const TAXONOMY_VERSION = "v6-weighted-scoring-b4";

// ── Helpers ──────────────────────────────────────────────────────────────────

function computeHash(entry) {
  // Simple deterministic hash der relevanten Felder für Sync-Validierung
  const relevant = [
    entry.industry_id,
    entry.label,
    entry.target_customer_types,
    entry.searchable_business_categories,
    entry.search_keyword_variants,
    entry.negative_keywords,
    entry.scoring_signals,
    entry.query_priority,
  ].map(v => typeof v === 'object' ? JSON.stringify(v) : String(v || '')).join('|');
  // FNV-1a 32-bit hash (keine Crypto-API nötig)
  let hash = 0x811c9dc5;
  for (let i = 0; i < relevant.length; i++) {
    hash ^= relevant.charCodeAt(i);
    hash = (hash * 0x01000193) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}

function parseJsonField(val, fallback = []) {
  if (!val) return fallback;
  if (Array.isArray(val) || typeof val === 'object') return val;
  try { return JSON.parse(val); } catch { return fallback; }
}

function dbEntryToProfile(entry) {
  return {
    id: entry.industry_id,
    label: entry.label,
    sort_order: entry.sort_order || 99,
    status: entry.status || 'production_ready',
    profile_group: entry.profile_group || null,
    aliases: parseJsonField(entry.aliases),
    ownServices: parseJsonField(entry.own_services),
    targetCustomerTypes: parseJsonField(entry.target_customer_types),
    excludedCustomerTypes: parseJsonField(entry.excluded_customer_types),
    searchableBusinessCategories: parseJsonField(entry.searchable_business_categories),
    searchKeywordVariants: parseJsonField(entry.search_keyword_variants, {}),
    negativeKeywords: parseJsonField(entry.negative_keywords),
    badFitSignals: parseJsonField(entry.bad_fit_signals),
    scoringSignals: parseJsonField(entry.scoring_signals),
    scoringSignalWeights: parseJsonField(entry.scoring_signal_weights, {}),
    badFitSignalWeights: parseJsonField(entry.bad_fit_signal_weights, {}),
    queryPriority: parseJsonField(entry.query_priority),
    idealCustomerProfiles: parseJsonField(entry.ideal_customer_profiles),
    googlePlaceTypes: parseJsonField(entry.google_place_types),
    placeTypeConfidence: entry.place_type_confidence || 'medium',
    searchStrategy: entry.search_strategy || 'target_customer_search',
    profileQualityScore: entry.profile_quality_score || null,
    profileQualityNotes: entry.profile_quality_notes || null,
    reviewedAt: entry.reviewed_at || null,
    content_hash: entry.content_hash,
    version: entry.version || TAXONOMY_VERSION,
  };
}

function seedEntryToDbRecord(seed) {
  return {
    industry_id: seed.industry_id,
    label: seed.label,
    version: TAXONOMY_VERSION,
    is_active: true,
    sort_order: seed.sort_order || 99,
    status: seed.status || 'production_ready',
    profile_group: seed.profile_group || null,
    aliases: JSON.stringify(seed.aliases || []),
    own_services: JSON.stringify(seed.own_services || []),
    target_customer_types: JSON.stringify(seed.target_customer_types || []),
    excluded_customer_types: JSON.stringify(seed.excluded_customer_types || []),
    searchable_business_categories: JSON.stringify(seed.searchable_business_categories || []),
    search_keyword_variants: JSON.stringify(seed.search_keyword_variants || {}),
    negative_keywords: JSON.stringify(seed.negative_keywords || []),
    bad_fit_signals: JSON.stringify(seed.bad_fit_signals || []),
    scoring_signals: JSON.stringify(seed.scoring_signals || []),
    scoring_signal_weights: JSON.stringify(seed.scoring_signal_weights || {}),
    bad_fit_signal_weights: JSON.stringify(seed.bad_fit_signal_weights || {}),
    query_priority: JSON.stringify(seed.query_priority || []),
    ideal_customer_profiles: JSON.stringify(seed.ideal_customer_profiles || []),
    google_place_types: JSON.stringify(seed.google_place_types || []),
    place_type_confidence: seed.place_type_confidence || 'medium',
    search_strategy: seed.search_strategy || 'target_customer_search',
    profile_quality_score: seed.profile_quality_score || null,
    profile_quality_notes: seed.profile_quality_notes || null,
    reviewed_at: seed.reviewed_at || null,
    content_hash: computeHash(seed),
  };
}

// ── MAIN ─────────────────────────────────────────────────────────────────────

Deno.serve(async (req) => {
  try {
    const base44 = createClientFromRequest(req);

    // Auth: öffentlicher Lesezugriff für Frontend-Onboarding + authenticated für Admin-Writes
    let user = null;
    try { user = await base44.auth.me(); } catch {}

    const body = await req.json().catch(() => ({}));
    const action = body.action || 'list'; // list | seed | get_single

    // ── list: alle aktiven Einträge zurückgeben ───────────────────────────────
    if (action === 'list') {
      let entries = await base44.asServiceRole.entities.TaxonomyEntry.filter(
        { is_active: true }, 'sort_order', 100
      );

      // Self-seeding: Falls DB leer, sequentiell schreiben (Rate-Limit-sicher)
      if (entries.length === 0) {
        console.info('[getTaxonomy] DB leer – initialisiere mit Seed-Daten...');
        for (const seed of TAXONOMY_SEED) {
          await base44.asServiceRole.entities.TaxonomyEntry.create(seedEntryToDbRecord(seed));
        }
        entries = await base44.asServiceRole.entities.TaxonomyEntry.filter(
          { is_active: true }, 'sort_order', 100
        );
        console.info(`[getTaxonomy] Seed abgeschlossen: ${entries.length} Einträge`);
      }

      const profiles = entries.map(dbEntryToProfile).sort((a, b) => a.sort_order - b.sort_order);

      // Taxonomy-Hash = Hash aller Entry-Hashes (Reihenfolge nach industry_id sort)
      const allHashes = profiles.map(p => p.content_hash || '').join('');
      let taxonomyHash = 0x811c9dc5;
      for (let i = 0; i < allHashes.length; i++) {
        taxonomyHash ^= allHashes.charCodeAt(i);
        taxonomyHash = (taxonomyHash * 0x01000193) >>> 0;
      }
      const taxonomy_hash = taxonomyHash.toString(16).padStart(8, '0');

      return Response.json({
        success: true,
        version: TAXONOMY_VERSION,
        taxonomy_hash,
        count: profiles.length,
        profiles,
      });
    }

    // ── seed_reset: Seed-Daten zurückschreiben (Admin only) ──────────────────
    if (action === 'seed_reset') {
      if (!user || !['admin', 'platform_owner', 'platform_admin'].includes(user.role)) {
        return Response.json({ error: 'Admin-Zugriff erforderlich', success: false }, { status: 403 });
      }
      // Upsert-Strategie: Update wenn vorhanden, Create wenn neu (minimal DB-Writes)
      const existing = await base44.asServiceRole.entities.TaxonomyEntry.filter({}, 'sort_order', 200);
      const existingById = {};
      for (const e of existing) existingById[e.industry_id] = e;

      let updated = 0, created = 0;
      for (const seed of TAXONOMY_SEED) {
        const record = { ...seedEntryToDbRecord(seed), is_active: true };
        const existing_entry = existingById[seed.industry_id];
        if (existing_entry) {
          await base44.asServiceRole.entities.TaxonomyEntry.update(existing_entry.id, record);
          updated++;
        } else {
          await base44.asServiceRole.entities.TaxonomyEntry.create(record);
          created++;
        }
      }
      // Nicht mehr im Seed vorhandene deaktivieren
      const seedIds = new Set(TAXONOMY_SEED.map(s => s.industry_id));
      for (const e of existing) {
        if (!seedIds.has(e.industry_id) && e.is_active) {
          await base44.asServiceRole.entities.TaxonomyEntry.update(e.id, { is_active: false });
        }
      }
      return Response.json({ success: true, message: `${updated} aktualisiert, ${created} neu`, version: TAXONOMY_VERSION });
    }

    // ── get_single: Einzelnen Eintrag per industry_id ────────────────────────
    if (action === 'get_single') {
      const { industry_id } = body;
      if (!industry_id) return Response.json({ error: 'industry_id fehlt', success: false }, { status: 400 });
      const entries = await base44.asServiceRole.entities.TaxonomyEntry.filter({ industry_id, is_active: true });
      if (!entries[0]) return Response.json({ error: 'Nicht gefunden', success: false }, { status: 404 });
      return Response.json({ success: true, profile: dbEntryToProfile(entries[0]) });
    }

    return Response.json({ error: 'Unbekannte Action', success: false }, { status: 400 });

  } catch (error) {
    console.error('[getTaxonomy] Error:', error?.message);
    return Response.json({ error: error?.message || 'Interner Fehler', success: false }, { status: 500 });
  }
});